import re

def anti_shuffle(s):
    tokens = re.findall(r'\S+|\s+', s)
    processed = []
    for token in tokens:
        if token.strip() == '':
            processed.append(token)
        else:
            sorted_token = ''.join(sorted(token))
            processed.append(sorted_token)
    return ''.join(processed)
